#!/usr/bin/env python3
import argparse
import csv
import json
import os
import subprocess
import sys
import time
from functools import lru_cache


def run_capture(cmd):
    proc = subprocess.run(cmd, stdout=subprocess.PIPE, stderr=subprocess.PIPE, text=True)
    return proc.returncode, proc.stdout.strip(), proc.stderr.strip()


def parse_csv_lines(raw):
    rows = []
    for line in raw.splitlines():
        line = line.strip()
        if not line:
            continue
        row = [field.strip() for field in next(csv.reader([line]))]
        rows.append(row)
    return rows


def query_gpus():
    cmd = [
        "nvidia-smi",
        "--query-gpu=index,uuid,memory.used,memory.total,utilization.gpu",
        "--format=csv,noheader,nounits",
    ]
    code, out, err = run_capture(cmd)
    if code != 0:
        raise RuntimeError(f"nvidia-smi failed: {err or out}")
    gpus = []
    for row in parse_csv_lines(out):
        if len(row) < 5:
            continue
        try:
            gpus.append(
                {
                    "index": int(row[0]),
                    "uuid": row[1],
                    "memory_used_mib": int(row[2]),
                    "memory_total_mib": int(row[3]),
                    "util_gpu": int(row[4]),
                }
            )
        except ValueError:
            continue
    return gpus


def query_compute_apps():
    cmd = [
        "nvidia-smi",
        "--query-compute-apps=gpu_uuid,pid,process_name,used_memory",
        "--format=csv,noheader,nounits",
    ]
    code, out, err = run_capture(cmd)
    if code != 0:
        msg = (err or out).lower()
        if "not found" in msg or "no running" in msg:
            return []
        return []
    apps = []
    for row in parse_csv_lines(out):
        if len(row) < 4:
            continue
        try:
            used_mem = int(row[3])
        except ValueError:
            used_mem = -1
        try:
            pid = int(row[1])
        except ValueError:
            continue
        apps.append(
            {
                "gpu_uuid": row[0],
                "pid": pid,
                "process_name": row[2],
                "used_memory_mib": used_mem,
            }
        )
    return apps


def query_tmux_panes():
    cmd = ["tmux", "list-panes", "-a", "-F", "#{session_name}\t#{window_name}\t#{pane_pid}"]
    code, out, _ = run_capture(cmd)
    if code != 0 or not out:
        return []
    panes = []
    for line in out.splitlines():
        parts = line.split("\t")
        if len(parts) != 3:
            continue
        try:
            pane_pid = int(parts[2])
        except ValueError:
            continue
        panes.append({"session": parts[0], "window": parts[1], "pane_pid": pane_pid})
    return panes


@lru_cache(maxsize=8192)
def get_ppid(pid):
    try:
        with open(f"/proc/{pid}/status", "r", encoding="utf-8", errors="ignore") as f:
            for line in f:
                if line.startswith("PPid:"):
                    return int(line.split()[1])
    except (FileNotFoundError, ProcessLookupError, PermissionError, ValueError):
        return 0
    return 0


def get_ancestors(pid, max_depth=128):
    cur = pid
    seen = set()
    for _ in range(max_depth):
        if cur <= 1 or cur in seen:
            break
        seen.add(cur)
        cur = get_ppid(cur)
    return seen


def find_tmux_owner(pid, panes):
    ancestors = get_ancestors(pid)
    for pane in panes:
        if pane["pane_pid"] in ancestors:
            return f"{pane['session']}:{pane['window']}"
    return "-"


def get_proc_cmd(pid):
    code, out, _ = run_capture(["ps", "-p", str(pid), "-o", "comm="])
    if code == 0 and out:
        return out.strip()
    return "unknown"


def summarize_owners(gpus, apps):
    uuid_to_index = {g["uuid"]: g["index"] for g in gpus}
    panes = query_tmux_panes()
    owners = []
    for app in apps:
        pid = app["pid"]
        proc = app["process_name"] or get_proc_cmd(pid)
        gpu_idx = uuid_to_index.get(app["gpu_uuid"], -1)
        tmux_owner = find_tmux_owner(pid, panes)
        owners.append(
            {
                "gpu": gpu_idx,
                "pid": pid,
                "proc": proc,
                "mem_mib": app["used_memory_mib"],
                "tmux": tmux_owner,
            }
        )
    owners.sort(key=lambda x: (x["gpu"], -x["mem_mib"], x["pid"]))
    return owners


def enough_free(gpus, min_free_gpus, max_used_mib):
